  '{"best_card":"Chase Sapphire Preferred","max_welcome_bonus_value":1000,"max_welcome_bonus_desc":"100,000 Ultimate Rewards pts ($1,000 via portal)","min_annual_fee":0,"max_annual_fee":550,"min_credit_score":700,"min_credit_label":"Good (700+)","has_travel_cards":true,"has_cashback_cards":true,"has_secured_card":false,"has_student_card":false,"has_business_card":true,"has_balance_transfer":true,"network":"Visa","app_store_rating":4.8,"review_source":"App Store iOS","regulatory_note":"JPMorgan Chase Bank N.A. — OCC-regulated national bank; FDIC-insured."}'::jsonb,
  'official', 'high',
