  8.5, 4.8, 1800000, 0, 0, 0, 0,
  '{"best_card":"Capital One Venture X","max_welcome_bonus_value":750,"max_welcome_bonus_desc":"75,000 miles (~$750 via travel portal)","min_annual_fee":0,"max_annual_fee":395,"min_credit_score":580,"min_credit_label":"Fair (580+)","has_travel_cards":true,"has_cashback_cards":true,"has_secured_card":true,"has_student_card":true,"has_business_card":true,"has_balance_transfer":true,"network":"Mastercard","app_store_rating":4.8,"review_source":"App Store iOS","regulatory_note":"Capital One Bank N.A. — OCC-regulated; FDIC-insured. Note: Discover is now a Capital One subsidiary (merger May 2025) — combined deposits share the $250k FDIC limit."}'::jsonb,
  'official', 'high',
  '[]'::jsonb,
  ARRAY['Full credit spectrum: fair to excellent','Venture X: $395 fee, $400 in annual credits back','Miles transfer to 15+ airline partners']::text[],
  ARRAY['Covers the full credit spectrum from fair (Platinum Secured, Quicksilver Student) to excellent (Venture X, Savor) — no other major issuer matches this range in one portfolio','Venture X ($395/year) returns $300 via travel portal credit + $100 Global Entry/TSA PreCheck credit, effectively netting down to -$5/year if you use both','Venture miles transfer to 15+ partners including Air Canada Aeroplan, Turkish Airlines Miles&Smiles, and Wyndham']::text[],
  ARRAY['Fewer premium transfer sweet-spots than Chase Ultimate Rewards or Amex Membership Rewards','Discover Bank is now a Capital One subsidiary (merger closed May 2025) — deposits at both banks share one $250k FDIC insurance limit','Some entry-level cards (Quicksilver) offer limited bonus categories vs. rivals at the same fee tier']::text[],
  '{"cost":8.6,"features":9.0,"ux":9.0,"support":8.2}'::jsonb,
  'The best all-in-one issuer for any credit score',
  'Capital One''s suite runs the full credit spectrum: the Venture X ($395/year, offset by $300 travel portal credit and $100 Global Entry/TSA PreCheck) targets premium travelers, while the Platinum Secured and Quicksilver Student cover fair/no credit applicants who no other major issuer will touch at competitive terms. Venture miles transfer to 15+ partners, though the program lacks the premium sweet spots of Chase''s or Amex''s networks. Discover Bank is now a Capital One subsidiary (merger completed May 2025) — it continues to operate as a separate brand, but combined deposits at both banks share the $250k FDIC insurance limit.',
  false, NULL, 'https://creditcards.capitalone.com/', false, 'Best for: All credit scores', 3,
  'https://creditcards.capitalone.com/', DATE '2026-07-05', true
