  '{"best_card":"Wells Fargo Active Cash","max_welcome_bonus_value":300,"max_welcome_bonus_desc":"$300 cash bonus (Active Cash)","min_annual_fee":0,"max_annual_fee":95,"min_credit_score":670,"min_credit_label":"Good (670+)","has_travel_cards":true,"has_cashback_cards":true,"has_secured_card":false,"has_student_card":false,"has_business_card":true,"has_balance_transfer":true,"network":"Visa","app_store_rating":4.8,"review_source":"App Store iOS","regulatory_note":"Wells Fargo Bank N.A. — OCC-regulated; FDIC-insured."}'::jsonb,
