  '{"best_card":"Credit One Bank Platinum Visa","max_welcome_bonus_value":0,"max_welcome_bonus_desc":"No welcome bonus","min_annual_fee":0,"max_annual_fee":99,"min_credit_score":300,"min_credit_label":"Bad credit OK (300+)","has_travel_cards":false,"has_cashback_cards":true,"has_secured_card":false,"has_student_card":false,"has_business_card":false,"has_balance_transfer":false,"network":"Visa","app_store_rating":4.1,"review_source":"App Store iOS","regulatory_note":"Credit One Bank N.A. — OCC-regulated; FDIC-insured."}'::jsonb,
