  5.5, 4.3, 45000, 0, 0, 0, 0,
  '{"best_card":"OpenSky Secured Visa","max_welcome_bonus_value":0,"max_welcome_bonus_desc":"No welcome bonus","min_annual_fee":0,"max_annual_fee":35,"min_credit_score":0,"min_credit_label":"None required","has_travel_cards":false,"has_cashback_cards":false,"has_secured_card":true,"has_student_card":false,"has_business_card":false,"has_balance_transfer":false,"network":"Visa","app_store_rating":4.3,"review_source":"App Store iOS","regulatory_note":"Capital Bank N.A. (issuer) — OCC-regulated; FDIC-insured."}'::jsonb,
  'official', 'medium',
  '[]'::jsonb,
  ARRAY['No credit check — anyone can apply','OpenSky Plus: $0 annual fee option','Credit builder: reports to all 3 bureaus']::text[],
  ARRAY['No credit check required — approval is based on ability to fund a security deposit, not credit history','Reports to Equifax, Experian, and TransUnion every month — responsible use builds or rebuilds a credit file from scratch','OpenSky Plus offers a $0 annual fee version; the Classic is $35/year but no credit check on either variant']::text[],
  ARRAY['No rewards of any kind on any OpenSky card','Must deposit $200–$3,000 as collateral — it is a secured card, not unsecured','Once your credit score reaches ~580–600, a Discover Secured or Capital One Platinum gives better terms']::text[],
  '{"cost":7.0,"features":4.0,"ux":6.8,"support":6.4}'::jsonb,
  'The only option if you need no credit check at all',
  'OpenSky is the only card on this list with no credit check at all — Capital Bank (the issuer) approves applicants based solely on their ability to make a security deposit ($200–$3,000), not their credit history. It''s the genuine last-resort credit builder: OpenSky reports to all three bureaus monthly, so responsible use does build credit. The OpenSky Plus offers a $0 annual fee version. Tradeoffs are real: no rewards, and the Classic card''s $35 annual fee eats into the credit-building value unless you switch to Plus. Once your credit score clears ~580–600, graduating to a Discover Secured or Capital One Platinum gives meaningfully better terms.',
  false, NULL, 'https://www.openskycc.com/', false, 'Best for: No credit check required', 10,
  'https://www.openskycc.com/', DATE '2026-07-05', true
)
